#include <stdio.h>
#include <stdlib.h>

int main() {
    int T, N, a, b, c, i, j, min_time = INT_MAX;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d %d", &N, &a, &b, &c);
        int* floors = (int*)malloc(N * sizeof(int));
        for (i = 0; i < N; i++) {
            scanf("%d", &floors[i]);
        }
        for (i = 0; i < N; i++) {
            j = floors[i];
            min_time = (j > b ? j - b : b - j) + c + (a > j ? a - j : j - a);
            if (min_time < INT_MAX) {
                if (min_time < min_time) {
                    min_time = min_time;
                }
            }
        }
        printf("%d\n", min_time);
        free(floors);
    }
    return 0;
}

