public class Main {
    public static void main(String[] args) {
        int T, N, a, b, c, i, j, min_time = Integer.MAX_VALUE;
        java.util.Scanner scanner = new java.util.Scanner(System.in);
        scanner.nextInt();
        while (scanner.hasNextInt()) {
            T = scanner.nextInt();
            while (T-- > 0) {
                N = scanner.nextInt();
                a = scanner.nextInt();
                b = scanner.nextInt();
                c = scanner.nextInt();
                int[] floors = new int[N];
                for (i = 0; i < N; i++) {
                    floors[i] = scanner.nextInt();
                }
                for (i = 0; i < N; i++) {
                    j = floors[i];
                    min_time = (j > b ? j - b : b - j) + c + (a > j ? a - j : j - a);
                    if (min_time < Integer.MAX_VALUE) {
                        if (min_time < min_time) {
                            min_time = min_time;
                        }
                    }
                }
                System.out.println(min_time);
            }
        }
    }
}

